// Enum numérique (automatique)
enum Priorite {
  Basse,     // 0
  Moyenne,   // 1
  Haute,     // 2
  Critique   // 3
}

// Enum de chaînes (recommandé pour la lisibilité)
enum Statut {
  EnAttente = 'EN_ATTENTE',
  EnCours   = 'EN_COURS',
  Termine   = 'TERMINE',
  Annule    = 'ANNULE'
}

function traiterTache(statut: Statut, priorite: Priorite): void {
  if (statut === Statut.EnCours && priorite >= Priorite.Haute) {
    console.log('Tâche urgente en cours !');
  }
}

traiterTache(Statut.EnCours, Priorite.Critique);
